const body = $input.first().json.body || {};

// Extract arguments and toolCallId
let args = body;
let toolCallId = body.toolCallId || "unknown";

if (body.message && body.message.toolWithToolCallList && body.message.toolWithToolCallList.length > 0) {
    const toolCall = body.message.toolWithToolCallList[0].toolCall;
    toolCallId = toolCall.id;
    args = toolCall.function.arguments || {};
} else if (body.message && body.message.toolCallList && body.message.toolCallList.length > 0) {
    const toolCall = body.message.toolCallList[0];
    toolCallId = toolCall.id;
    args = toolCall.function ? toolCall.function.arguments : (toolCall.arguments || {});
}

// Handle stringified arguments
if (typeof args === 'string') {
    try {
        args = JSON.parse(args);
    } catch (e) {
        args = {};
    }
}

let dateStr = args.date || args.day || "";
let timeStr = (args.time || args.hour || "").toString().trim();
let dateTimeStr = args.dateTime || args.datetime || args.date_time || "";
let durationMinutes = Number(args.duration_minutes || args.duration || 30);

let year, month, day, hour, minute;
let parsedFromDateTime = false;

// Helper
const pad = (num) => String(num).padStart(2, '0');

// 1. Try to parse from combined dateTime string
if (dateTimeStr) {
    try {
        let cleanDT = dateTimeStr.replace(/(st|nd|rd|th)\b/gi, '').replace(/\bat\b/gi, '').trim();

        // Handle relative dates
        const now = new Date();
        const todayStr = `${now.getFullYear()}-${pad(now.getMonth()+1)}-${pad(now.getDate())}`;

        if (cleanDT.toLowerCase().includes('today')) {
            cleanDT = cleanDT.replace(/today/gi, todayStr);
        } else if (cleanDT.toLowerCase().includes('tomorrow')) {
            const tomorrow = new Date(now);
            tomorrow.setDate(tomorrow.getDate() + 1);
            const tomorrowStr = `${tomorrow.getFullYear()}-${pad(tomorrow.getMonth()+1)}-${pad(tomorrow.getDate())}`;
            cleanDT = cleanDT.replace(/tomorrow/gi, tomorrowStr);
        }

        // Convert "3 PM" to "3:00 PM" for better parsing
        cleanDT = cleanDT.replace(/\b(\d{1,2})\s*(AM|PM)\b/gi, '$1:00 $2');

        let parsedDate = new Date(cleanDT);

        // Force year to 2026 if it's in the past
        if (parsedDate.getFullYear() < 2026) {
            parsedDate.setFullYear(2026);
        }

        if (!isNaN(parsedDate.getTime())) {
            year = parsedDate.getFullYear();
            month = parsedDate.getMonth() + 1;
            day = parsedDate.getDate();
            hour = parsedDate.getHours();
            minute = parsedDate.getMinutes();
            parsedFromDateTime = true;

            dateStr = `${year}-${pad(month)}-${pad(day)}`;
            timeStr = `${pad(hour)}:${pad(minute)}`;
        }
    } catch (e) {
        parsedFromDateTime = false;
    }
}

// 2. Fallback to parsing separate date & time parameters
if (!parsedFromDateTime) {

    // Try to extract day name from dateTimeStr
    let targetDate = new Date();
    let dayNameMatched = false;

    if (dateTimeStr) {
        const lowerDT = dateTimeStr.toLowerCase();
        const dayNames = ['sunday', 'monday', 'tuesday', 'wednesday', 'thursday', 'friday', 'saturday'];
        const dayIndex = dayNames.findIndex(d => lowerDT.includes(d));

        if (dayIndex !== -1) {
            // Found a day name — calculate the next occurrence
            const today = new Date();
            const todayDay = today.getDay();
            let daysUntil = dayIndex - todayDay;
            if (daysUntil <= 0) daysUntil += 7; // Next week if today or past

            targetDate = new Date(today);
            targetDate.setDate(today.getDate() + daysUntil);
            dayNameMatched = true;
        } else if (lowerDT.includes('tomorrow')) {
            targetDate = new Date();
            targetDate.setDate(targetDate.getDate() + 1);
        } else if (lowerDT.includes('today')) {
            targetDate = new Date();
        }
    }

    if (!dateStr) {
        const yyyy = targetDate.getFullYear();
        const mm = String(targetDate.getMonth() + 1).padStart(2, '0');
        const dd = String(targetDate.getDate()).padStart(2, '0');
        dateStr = `${yyyy}-${mm}-${dd}`;
    }

    // Extract time from dateTimeStr if available
    if (!timeStr && dateTimeStr) {
        const timeMatch = dateTimeStr.match(/(\d{1,2})(?::(\d{2}))?\s*(am|pm|AM|PM)?/i);
        if (timeMatch) {
            let h = parseInt(timeMatch[1]);
            let m = timeMatch[2] ? parseInt(timeMatch[2]) : 0;
            let ampm = timeMatch[3] ? timeMatch[3].toLowerCase() : '';
            if (ampm === 'pm' && h < 12) h += 12;
            if (ampm === 'am' && h === 12) h = 0;
            timeStr = `${String(h).padStart(2, '0')}:${String(m).padStart(2, '0')}`;
        }
    }

    if (!timeStr) {
        timeStr = '09:00';
    }

    try {
        [year, month, day] = dateStr.split('T')[0].split('-').map(Number);

        const normalizedTime = timeStr.toLowerCase().replace('om', 'pm');
        const isPM = normalizedTime.includes('pm');
        const isAM = normalizedTime.includes('am');

        let cleanTime = normalizedTime.replace(/[^0-9:]/g, ''); 
        let timeParts = cleanTime.split(':');
        hour = Number(timeParts[0]);
        minute = timeParts[1] ? Number(timeParts[1]) : 0;

        if (isPM && hour < 12) {
            hour += 12;
        } else if (isAM && hour === 12) {
            hour = 0;
        }
    } catch (e) {
        const d = new Date();
        year = d.getFullYear(); month = d.getMonth() + 1; day = d.getDate();
        hour = 9; minute = 0;
    }
}

// 3. Determine Day of the Week
let dayOfWeek = 1;
try {
    const parsedDate = new Date(year, month - 1, day);
    dayOfWeek = parsedDate.getDay();
} catch (e) {}

const startISO = `${year}-${pad(month)}-${pad(day)}T${pad(hour)}:${pad(minute)}:00.000Z`;

let endHour = hour;
let endMinute = minute + durationMinutes;
if (endMinute >= 60) {
    endHour += Math.floor(endMinute / 60);
    endMinute = endMinute % 60;
}
const endISO = `${year}-${pad(month)}-${pad(day)}T${pad(endHour)}:${pad(endMinute)}:00.000Z`;

// Business hours check
const isWeekend = (dayOfWeek === 0 || dayOfWeek === 6);
const isOutsideTime = (hour < 9 || hour >= 17);
const isOutsideHours = isWeekend || isOutsideTime;

// Business day range for calendar query
const businessStartISO = `${year}-${pad(month)}-${pad(day)}T09:00:00.000Z`;
const businessEndISO = `${year}-${pad(month)}-${pad(day)}T17:00:00.000Z`;

return [{
  json: {
    toolCallId: toolCallId,
    date: dateStr,
    time: timeStr,
    startISO: startISO,
    endISO: endISO,
    businessStartISO: businessStartISO,
    businessEndISO: businessEndISO,
    outsideBusinessHours: isOutsideHours,
    isWeekend: isWeekend
  }
}];

const parsed = $('Code - Parse Requested Slot').first().json || {};
const toolCallId = parsed.toolCallId || "unknown";
const outsideHours = parsed.outsideBusinessHours || false;
const isWeekend = parsed.isWeekend || false;

// 1. Gather Google Calendar events and filter out empty items
let events = [];
try {
    events = $input.all()
        .map(item => item.json)
        .filter(event => {
            if (!event || Object.keys(event).length === 0) return false;
            const hasStart = event.start || event.startISO || (event.start && event.start.dateTime);
            return !!hasStart;
        });
} catch (e) {
    events = [];
}

let displayTime = parsed.time || "that time";
let displayDate = parsed.date || "that day";

// Helper: 12-hour formatting
if (parsed.time && parsed.time.includes(':')) {
    try {
        const [h, m] = parsed.time.split(':').map(Number);
        const ampm = h >= 12 ? 'PM' : 'AM';
        const displayHour = h % 12 || 12;
        const displayMin = m < 10 ? '0' + m : m;
        displayTime = `${displayHour}:${displayMin} ${ampm}`;
    } catch (e) {}
}

// Helper: Friendly date formatting
if (parsed.date && parsed.date.includes('-')) {
    try {
        const months = [
            "January", "February", "March", "April", "May", "June", 
            "July", "August", "September", "October", "November", "December"
        ];
        const [y, m, d] = parsed.date.split('-').map(Number);
        let suffix = "th";
        if (d === 1 || d === 21 || d === 31) suffix = "st";
        else if (d === 2 || d === 22) suffix = "nd";
        else if (d === 3 || d === 23) suffix = "rd";
        displayDate = `${months[m - 1]} ${d}${suffix}`;
    } catch (e) {}
}

// 2. Outside Business Hours Block
if (outsideHours) {
    let closedMessage = `I'm sorry, but ${displayTime} is outside of our regular business hours. We are open from 9:00 AM to 5:00 PM. Is there another time you'd like to try?`;

    // Custom message specifically for weekends
    if (isWeekend) {
        closedMessage = `I'm sorry, but we are completely closed on weekends. Our business hours are Monday through Friday, 9:00 AM to 5:00 PM. Is there a weekday you would like to book instead?`;
    }

    return [{
        json: {
            toolCallId: toolCallId,
            available: false,
            result: closedMessage
        }
    }];
}

// 3. Conflict Detection Logic
let hasConflict = false;
const reqStart = new Date(parsed.startISO).getTime();
const reqEnd = new Date(parsed.endISO).getTime();

if (!isNaN(reqStart) && !isNaN(reqEnd)) {
    for (const event of events) {
        const eventStartStr = event.start ? (event.start.dateTime || event.start) : event.startISO;
        const eventEndStr = event.end ? (event.end.dateTime || event.end) : event.endISO;

        if (!eventStartStr || !eventEndStr) continue;

        const evStart = new Date(eventStartStr).getTime();
        const evEnd = new Date(eventEndStr).getTime();

        if (isNaN(evStart) || isNaN(evEnd)) continue;

        if (reqStart < evEnd && reqEnd > evStart) {
            hasConflict = true;
            break;
        }
    }
}

// 4. Construct response
let conversationalMessage = "";
if (hasConflict) {
    conversationalMessage = `I'm sorry, but ${displayTime} on ${displayDate} is actually already booked. Is there another day or time that works for you?`;
} else {
    conversationalMessage = `Yes, ${displayTime} on ${displayDate} is completely open! Would you like me to go ahead and book that for you?`;
}

return [{
  json: {
    toolCallId: toolCallId,
    result: conversationalMessage
  }
}];

