// TIMEZONE CONFIGURATION - Change this to your timezone offset
const TIMEZONE_OFFSET_HOURS = 5;

// Helper to adjust hour for timezone offset
function adjustForTimezone(y, m, d, h, min, offset) {
    let adjustedHour = h - offset;
    let adjustedDay = d;
    let adjustedMonth = m;
    let adjustedYear = y;

    if (adjustedHour < 0) {
        adjustedHour += 24;
        adjustedDay -= 1;
        if (adjustedDay < 1) {
            adjustedMonth -= 1;
            if (adjustedMonth < 1) {
                adjustedMonth = 12;
                adjustedYear -= 1;
            }
            adjustedDay = new Date(adjustedYear, adjustedMonth, 0).getDate();
        }
    } else if (adjustedHour >= 24) {
        adjustedHour -= 24;
        adjustedDay += 1;
        const lastDayOfMonth = new Date(adjustedYear, adjustedMonth, 0).getDate();
        if (adjustedDay > lastDayOfMonth) {
            adjustedDay = 1;
            adjustedMonth += 1;
            if (adjustedMonth > 12) {
                adjustedMonth = 1;
                adjustedYear += 1;
            }
        }
    }

    return {
        year: adjustedYear,
        month: adjustedMonth,
        day: adjustedDay,
        hour: adjustedHour,
        minute: min
    };
